using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class ModelTrainingService
{
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public string ModelPath => _modelPath;

    public void TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Featurize text columns and combine with Priority into a single Features vector
        var pipeline = mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue(
                "PredictedLabel", "PredictedLabel"));

        _logger.LogInformation("Training model with {Rows} total rows...", GetRowCount(data));

        ITransformer model = pipeline.Fit(split.TrainSet);

        // Evaluate on held-out test set
        IDataView predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("  Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("  Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);

        LogConfusionMatrix(metrics.ConfusionMatrix);

        mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }

    private static long GetRowCount(IDataView data)
    {
        long count = 0;
        var cursor = data.GetRowCursor(data.Schema);
        while (cursor.MoveNext()) count++;
        return count;
    }

    private void LogConfusionMatrix(Microsoft.ML.Data.ConfusionMatrix matrix)
    {
        _logger.LogInformation("=== Confusion Matrix ===");

        var categories = Enumerable.Range(0, matrix.NumberOfClasses)
            .Select(i => matrix.GetFormattedConfusionTable()
                .Split('\n')
                .Skip(1)
                .Where(line => !string.IsNullOrWhiteSpace(line))
                .ToArray())
            .First();

        // Log the full formatted table from ML.NET
        foreach (var line in matrix.GetFormattedConfusionTable().Split('\n'))
        {
            if (!string.IsNullOrWhiteSpace(line))
                _logger.LogInformation("  {Line}", line);
        }

        for (int i = 0; i < matrix.PerClassPrecision.Count; i++)
        {
            _logger.LogInformation("  Class {Index}: Precision={Precision:F4}, Recall={Recall:F4}",
                i, matrix.PerClassPrecision[i], matrix.PerClassRecall[i]);
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    public TicketsController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    /// <summary>
    /// Classifies a support ticket into Billing, Technical, or General.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (!ModelState.IsValid)
            return ValidationProblem();

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        string[] labels = ["Billing", "General", "Technical"];
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }
}

