using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

var app = builder.Build();

// Train the model at startup and log evaluation metrics
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndEvaluate();

// Register the pooled prediction engine with the trained model
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild the service provider to include the prediction pool
app = builder.Build();

app.MapControllers();
app.Run();

