    {
        _logger.LogInformation("=== Confusion Matrix ===");
        foreach (var line in matrix.GetFormattedConfusionTable().Split('\n'))
        {
            if (!string.IsNullOrWhiteSpace(line))
                _logger.LogInformation("  {Line}", line);
        }

